// countRunning counts the number of running workers.
func countRunning(workers []worker.WorkerInfo) int {
	count := 0
	for _, w := range workers {
		if w.Running {
			count++
		}
	}

	return count
}

// countErrors counts the number of workers with errors.
func countErrors(workers []worker.WorkerInfo) int {
	count := 0
	for _, w := range workers {
		if w.LastErr != "" {
			count++
		}
	}

	return count
}

